import { ToolNode } from 'flowise';

const safetyPatterns = [
  /\b(?:rm|del|drop|delete|truncate)\b.*\b(?:table|database|file)\b/i,
  /\bsystem\b.*\boverride\b/i,
  /\bexec\b|\bshell\b|\bcommand\b/i
];

const scanToolInput = (input: string): { safe: boolean; risk: string } => {
  for (const pattern of safetyPatterns) {
    if (pattern.test(input)) {
      return { safe: false, risk: 'Dangerous command detected' };
    }
  }
  return { safe: true, risk: 'none' };
};

// Global tool safety handler
const safeToolNode = new ToolNode();
safeToolNode.setInputValidator((input) => {
  const result = scanToolInput(input);
  if (!result.safe) {
    throw new Error(`Tool blocked: ${result.risk}`);
  }
  return input;
});

