import { ChatFlow } from 'flowise';

const piiRedactor = {
  maskPII: (text: string): string => {
    const patterns = {
      ssn: /\b\d{3}-\d{2}-\d{4}\b/g,
      email: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,
      phone: /\b\+?\d{1,4}?[-.\s]?\(?\d{1,3}\)?[-.\s]?\d{1,4}[-.\s]?\d{1,4}[-.\s]?\d{1,9}\b/g
    };

    let cleaned = text;
    for (const [type, pattern] of Object.entries(patterns)) {
      cleaned = cleaned.replace(pattern, `[REDACTED_${type.toUpperCase()}]`);
    }
    return cleaned;
  }
};

// Apply to all chatflow outputs
const chatflow = new ChatFlow();
chatflow.setOutputProcessor((output) => {
  return {
    ...output,
    content: piiRedactor.maskPII(output.content)
  };
});

