import { AgentNode, ChatFlow } from 'flowise';

interface GovernanceContext {
  sessionId: string;
  policyVersion: string;
  riskScore: number;
  auditTrail: string[];
}

const contextBridge = {
  extractContext: (input: any): GovernanceContext => ({
    sessionId: input.sessionId || 'unknown',
    policyVersion: 'v1.0',
    riskScore: input.riskScore || 0,
    auditTrail: input.auditTrail || []
  }),

  injectContext: (output: any, context: GovernanceContext) => ({
    ...output,
    governance: context,
    auditTrail: [...context.auditTrail, `Agent:${output.agentId}`]
  })
};

// Apply to agent handoffs
const agentA = new AgentNode();
agentA.setOutputHandler((output) => {
  const ctx = contextBridge.extractContext(output);
  return contextBridge.injectContext(output, ctx);
});

